import java.io.*;class Main{static int solve(int[] bulbs,int k){int n=bulbs.length;int[] days=new int[n];for(int i=0;i<n;i++)days[bulbs[i]-1]=i+1;int ans=Integer.MAX_VALUE/4,left=0,right=k+1;while(right<n){boolean valid=true;for(int i=left+1;i<right;i++){if(days[i]<Math.max(days[left],days[right])){left=i;right=i+k+1;valid=false;break;}}if(valid){ans=Math.min(ans,Math.max(days[left],days[right]));left=right;right=left+k+1;}}return ans>=Integer.MAX_VALUE/8?-1:ans;}public static void main(String[] a)throws Exception{String text=new String(System.in.readAllBytes()).trim();if(text.isEmpty())return;String[] d=text.split("\\s+");int idx=0,t=Integer.parseInt(d[idx++]);StringBuilder out=new StringBuilder();for(int tc=0;tc<t;tc++){int n=Integer.parseInt(d[idx++]),k=Integer.parseInt(d[idx++]);int[] bulbs=new int[n];for(int i=0;i<n;i++)bulbs[i]=Integer.parseInt(d[idx++]);if(tc>0)out.append("\n\n");out.append(solve(bulbs,k));}System.out.print(out);}}
